interface.definition:
a!localVariables(
  local!report1: "<ul><li><p><strong>Datum:</strong> 20. Februar 2025<br /><strong>Inhalt:</strong> Er zeigte sich w" & fn!char(228) & "hrend des Gespr" & fn!char(228) & "chs kooperativ und reflektiert. Er sprach offen " & fn!char(252) & "ber seine Vergangenheit und die Gr" & fn!char(252) & "nde f" & fn!char(252) & "r seine Inhaftierung. Er " & fn!char(228) & "u" & fn!char(223) & "erte den Wunsch, an Rehabilitationsprogrammen teilzunehmen und sich weiterzubilden.</p></li><li><p><strong>Datum:</strong> 25. Februar 2025<br /><strong>Inhalt:</strong> Er berichtete " & fn!char(252) & "ber Fortschritte in seinem Verhalten und seine Teilnahme an den angebotenen Programmen. Er zeigte Interesse an einer beruflichen Weiterbildung und fragte nach M" & fn!char(246) & "glichkeiten, nach seiner Entlassung eine Arbeit zu finden.</p></li></ul>",
  local!report2: "<ul><li><p>Er nutzt regelm" & fn!char(228)& fn!char(223) & "ig die Bibliothek und hat sich mehrere B" & fn!char(252) & "cher zu den Themen Pers" & fn!char(246) & "nlichkeitsentwicklung und berufliche Weiterbildung ausgeliehen.</p></li><li><p>Er hat Zugang zu einem Computer und nutzt diesen haupts" & fn!char(228) & "chlich f" & fn!char(252) & "r Bildungszwecke, wie das Erlernen neuer F" & fn!char(228) & "higkeiten und das Schreiben von Bewerbungen.</p></li></ul>",
  local!report3: "<ul><li><p><strong>Holzwerkstatt:</strong> Er arbeitet seit Januar 2025 in der Holzwerkstatt. Seine Vorgesetzten berichten, dass er zuverl" & fn!char(228) & "ssig und engagiert ist. Er hat bereits mehrere Projekte erfolgreich abgeschlossen und zeigt gro" & fn!char(223) & "es handwerkliches Geschick.</p></li><li><p><strong>K" & fn!char(252) & "che:</strong> Er hat auch in der K" & fn!char(252) & "che ausgeholfen und sich als teamf" & fn!char(228) & "hig und lernbereit erwiesen. Er hat sich schnell in die Abl" & fn!char(228) & "ufe eingearbeitet und unterst" & fn!char(252) & "tzt das K" & fn!char(252) & "chenteam tatkr" & fn!char(228) & "ftig.</p></li></ul>",
  local!report4: "<ul><li><p>Er zeigt insgesamt ein positives Verhalten und h" & fn!char(228) & "lt sich an die Regeln des Gef" & fn!char(228) & "ngnisses. Er hat keine Disziplinarverst" & fn!char(246)& fn!char(223) & "e und wird von den Mitinsassen respektiert.</p></li><li><p>Er nimmt regelm" & fn!char(228)& fn!char(223) & "ig an den angebotenen Sport- und Freizeitaktivit" & fn!char(228) & "ten teil und zeigt dabei eine positive Einstellung.</p></li></ul>",
  local!report5: "<p>Er zeigt deutliche Fortschritte in seiner Rehabilitation. Er ist motiviert, an seiner pers" & fn!char(246) & "nlichen und beruflichen Entwicklung zu arbeiten, und nutzt die angebotenen Ressourcen effektiv. Es wird empfohlen, ihm weiterhin Zugang zu Bildungs- und Rehabilitationsprogrammen zu gew" & fn!char(228) & "hren und ihn bei der Vorbereitung auf seine Entlassung zu unterst" & fn!char(252) & "tzen.</p>",
  local!question,
  #"SYSTEM_SYSRULES_formLayout_v1"(
    backgroundColor: "WHITE",
    label: "Besuchsantrag Prüfen",
    instructions: "Hier kommt eine konkrete Beschreibung der Aufgabe,",
    contents: {
      #"SYSTEM_SYSRULES_columnsLayout"(
        columns: {
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_sectionLayout_v1"(
                label: "Antrag",
                labelIcon: "address-book",
                contents: {
                  #"SYSTEM_SYSRULES_cardLayout"(
                    contents: {
                      #"SYSTEM_SYSRULES_textField"(
                        label: "Antragsteller",
                        labelPosition: "JUSTIFIED",
                        value: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1546843"(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3ae6d220-0450-4065-b61f-4b136d605959"]),
                        readOnly: true
                      ),
                      #"SYSTEM_SYSRULES_dateField"(
                        label: "Datum",
                        labelPosition: "JUSTIFIED",
                        value: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/1248a4bf-108e-4870-8db8-2816b7cd4bea"],
                        readOnly: true
                      ),
                      #"SYSTEM_SYSRULES_textField"(
                        label: "Gäste",
                        labelPosition: "JUSTIFIED",
                        value: joinarray(split(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"], ";"), ", "),
                        readOnly: true
                      ),
                      #"SYSTEM_SYSRULES_paragraphField"(
                        label: "Grund",
                        labelPosition: "ABOVE",
                        value: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/71d51822-db2b-4543-b00e-364428dbdfbc"],
                        showCharacterCount: false,
                        readOnly: true
                      )
                    },
                    style: "INFO",
                    shape: "ROUNDED",
                    showBorder: false,
                    showShadow: true
                  )
                }
              ),
              #"SYSTEM_SYSRULES_sectionLayout_v1"(
                label: "Rückfrage",
