                        labelPosition: "ABOVE",
                        value: ri!question,
                        showCharacterCount: false,
                        readOnly: true
                      ),
                      #"SYSTEM_SYSRULES_paragraphField"(
                        label: "Antwort",
                        labelPosition: "ABOVE",
                        value: ri!answer,
                        showCharacterCount: false,
                        readOnly: true
                      )
                    },
                    style: "INFO",
                    shape: "ROUNDED",
                    showBorder: false,
                    showShadow: true
                  )
                },
                showWhen: a!isNotNullOrEmpty(ri!answer)
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_sectionLayout_v1"(
                label: "KI-Führungsbericht " & #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1546843"(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3ae6d220-0450-4065-b61f-4b136d605959"]),
                labelIcon: "info",
                contents: {
                  #"SYSTEM_SYSRULES_cardLayout"(
                    contents: {
                      #"SYSTEM_SYSRULES_sideBySideLayout"(
                        items: {
                          #"SYSTEM_SYSRULES_sideBySideItem"(
                            item: #"SYSTEM_SYSRULES_styledTextEditorField"(
                              label: "Styled Text Editor",
                              labelPosition: "COLLAPSED",
                              value: local!report5,
                              sizeLimit: 4000,
                              height: "MEDIUM",
                              readOnly: true
                            )
                          ),
                          #"SYSTEM_SYSRULES_sideBySideItem"(
                            item: #"SYSTEM_SYSRULES_stampField"(
                              labelPosition: "COLLAPSED",
                              text: "42",
                              contentColor: "STANDARD",
                              size: "SMALL"
                            ),
                            width: "MINIMIZE"
                          )
                        }
                      ),
                      #"SYSTEM_SYSRULES_sectionLayout_v1"(
                        label: "Gesprächsprotokolle",
                        labelSize: "SMALL",
                        contents: {
                          #"SYSTEM_SYSRULES_styledTextEditorField"(
                            label: "Styled Text Editor",
                            labelPosition: "COLLAPSED",
                            value: local!report1,
                            sizeLimit: 4000,
                            height: "MEDIUM",
                            readOnly: true
                          )
                        },
                        isCollapsible: true,
                        isInitiallyCollapsed: true
                      ),
                      #"SYSTEM_SYSRULES_sectionLayout_v1"(
                        label: "Mediennutzung",
                        labelSize: "SMALL",
                        contents: {
                          #"SYSTEM_SYSRULES_styledTextEditorField"(
                            label: "Styled Text Editor",
                            labelPosition: "COLLAPSED",
                            value: local!report2,
                            sizeLimit: 4000,
                            height: "MEDIUM",
                            readOnly: true
                          )
                        },
                        isCollapsible: true,
                        isInitiallyCollapsed: true
                      ),
                      #"SYSTEM_SYSRULES_sectionLayout_v1"(
                        label: "Berichte aus den Werkstätten",
                        labelSize: "SMALL",
                        contents: {
                          #"SYSTEM_SYSRULES_styledTextEditorField"(
                            label: "Styled Text Editor",
                            labelPosition: "COLLAPSED",
                            value: local!report3,
                            sizeLimit: 4000,
                            height: "MEDIUM",
                            readOnly: true
                          )
                        },
                        isCollapsible: true,
                        isInitiallyCollapsed: true
                      ),
                      #"SYSTEM_SYSRULES_sectionLayout_v1"(
                        label: "Allgemeines Verhalten",
                        labelSize: "SMALL",
                        contents: {
                          #"SYSTEM_SYSRULES_styledTextEditorField"(
                            label: "Styled Text Editor",
                            labelPosition: "COLLAPSED",
                            value: local!report4,
                            sizeLimit: 4000,
                            height: "MEDIUM",
                            readOnly: true
                          )
                        },
                        isCollapsible: true,
                        isInitiallyCollapsed: true
                      )
                    },
                    style: "INFO",
                    shape: "ROUNDED",
                    showBorder: false,
                    showShadow: true
                  )
                }
              )
            }
          )
        }
      ),
      #"SYSTEM_SYSRULES_sectionLayout_v1"(
        label: "Verlauf",
        labelIcon: "archive",
        contents: {
          #"SYSTEM_SYSRULES_eventHistoryListField"(
            label: "Event History",
            labelPosition: "COLLAPSED",
            eventData: {
              #"SYSTEM_SYSRULES_eventData"(
                recordType: #"urn:appian:record-type:v1:f4e3c5fd-9f99-496e-a23f-31f98c2db72c",
                filters: #"SYSTEM_SYSRULES_queryLogicalExpression"(
                  operator: "AND",
                  filters: {
                    #"SYSTEM_SYSRULES_queryFilter"(
                      field: #"urn:appian:record-field:v1:f4e3c5fd-9f99-496e-a23f-31f98c2db72c/275590f7-3a7d-4cae-bbb7-bdae5b7762bf",
                      operator: "=",
                      value: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/1a44d310-f607-46fd-b655-3e8724b79bb1"]
                    )
                  },
                  ignoreFiltersWithEmptyValues: true
                ),
                timestamp: #"urn:appian:record-field:v1:f4e3c5fd-9f99-496e-a23f-31f98c2db72c/24b298d0-2be4-4bf2-be68-a93be0aef46d",
                user: #"urn:appian:record-field:v1:f4e3c5fd-9f99-496e-a23f-31f98c2db72c/32758b2d-59d8-4508-9329-cbf9bbd86755",
                comment: #"urn:appian:record-field:v1:f4e3c5fd-9f99-496e-a23f-31f98c2db72c/e578215d-41ce-41f3-a3f3-6deecb089557",
                eventTypeName: fv!data[#"urn:appian:record-field:v1:f4e3c5fd-9f99-496e-a23f-31f98c2db72c/4752c7d0-05d4-431f-9297-8a03f59ab709/4f6952ac-b5c9-4ba2-bf7c-e7f39a669914"]
              )
            },
            refreshAfter: "RECORD_ACTION",
            eventStyle: "LIST_WITH_COMMENTS",
            showSearchBox: true,
            showReverseSortButton: true
          )
        },
        isCollapsible: true,
        isInitiallyCollapsed: true
      ),
      #"SYSTEM_SYSRULES_sectionLayout_v1"(
        label: "Entscheidung",
        labelIcon: "balance-scale",
        contents: {
          #"SYSTEM_SYSRULES_cardLayout"(
            contents: {
              #"SYSTEM_SYSRULES_cardChoiceField"(
                label: "Card Choices",
                labelPosition: "COLLAPSED",
                data: {
                  a!map(id: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068423", icon: "thumbs-up", primaryText: "Ja", secondaryText: "Besuch genehmigen"),
                  a!map(id: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1075332", icon: "question", primaryText: "Rückfrage", secondaryText: "Rückfrage an Antragsteller"),
                  a!map(id: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068411", icon: "user-tie", primaryText: "Delegieren", secondaryText: "Prüfung durch Andere"),
                  a!map(id: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068417", icon: "thumbs-down", primaryText: "Nein", secondaryText: "Besuch ablehnen")
                },
                cardTemplate: #"SYSTEM_SYSRULES_cardTemplateTile"(
                  id: fv!data.id,
                  primaryText: fv!data.primaryText,
                  secondaryText: fv!data.secondaryText,
                  icon: fv!data.icon
                ),
                value: ri!decision,
                saveInto: ri!decision,
                maxSelections: 1,
                align: "CENTER",
                showShadow: true,
                required: true
              ),
              #"SYSTEM_SYSRULES_pickerFieldUsers"(
                label: "Weitere Prüfung durch",
                maxSelections: 1,
                value: ri!delegateUser,
                saveInto: ri!delegateUser,
                showWhen: ri!decision = #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068411",
                required: true
              ),
              #"SYSTEM_SYSRULES_paragraphField"(
                label: "Kommentar",
                value: ri!comment,
                saveInto: ri!comment,
                height: "MEDIUM",
                showWhen: ri!decision <> #"_a-0000ed87-2144-8000-9bee-011c48011c48_1075332",
                required: true
              ),
              #"SYSTEM_SYSRULES_paragraphField"(
                label: "Rückfrage",
                value: local!question,
                saveInto: local!question,
                height: "MEDIUM",
                showWhen: ri!decision = #"_a-0000ed87-2144-8000-9bee-011c48011c48_1075332",
                required: true
              )
            },
            style: "INFO",
            shape: "ROUNDED",
            showBorder: false,
            showShadow: true
          )
        }
      ),
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
        text: {
          "Der Antragsteller erhält eine Nachricht über deine Entscheidung.",
          "Die Gäste werden per Email eingeladen.",
          "In der Zugangsverwaltung werden die Gäste für dieses Datum angelegt."
        },
        showWhen: ri!decision = #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068423"
      ),
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
        text: {
          "Der Antragsteller erhält eine Nachricht über deine Entscheidung."
        },
        showWhen: ri!decision = #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068417"
      ),
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
        text: {
          "Der ausgewählte Benutzer bekommt eine Aufgabe zur Prüfung des Antrags."
        },
        showWhen: ri!decision = #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068411"
      ),
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
        text: {
          "Der Antragsteller erhält eine Aufgabe in der er deine Rückfrage beantwortet.",
          "Du erhälst dann diesen Antrag zur erneuten Prüfung.",
          "Der Antragsteller hat 2 Tage Zeit. Danach wird dein Antrag verworfen."
        },
        showWhen: ri!decision = #"_a-0000ed87-2144-8000-9bee-011c48011c48_1075332"
      )
    },
    buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
